def main():
    # Parse the JSON data
    issues = json.loads(json_data)
    
    # Find AI Agent Tracker issues
    tracker_issues = []
    framework_issues = []
    
    for issue in issues:
        title = issue['title'].lower()
        if 'ai agent' in title and 'tracker' in title:
            tracker_issues.append(issue['number'])
        elif 'ai agent framework' in title:
            framework_issues.append(issue['number'])
    
    print("AI Agent Tracker issues to tag as duplicates:")
    for issue_num in tracker_issues:
        print(f"  #{issue_num}")
        
    print("\nAI Agent Framework issues to tag as duplicates:")
    for issue_num in framework_issues:
        print(f"  #{issue_num}")
    
    # Add the duplicate label to these issues
    print("\nApplying 'duplicate' label to AI Agent Tracker issues...")
    for issue_num in tracker_issues:
        if issue_num != 2687:  # Skip the one we already tagged
            try:
                result = subprocess.run(['gh', 'issue', 'edit', str(issue_num), '--add-label', 'duplicate'], 
                                      cwd='/Users/huohao/Repositories/ossinsight', 
                                      capture_output=True, text=True)
                if result.returncode == 0:
                    print(f"  Successfully added duplicate label to #{issue_num}")
                else:
                    print(f"  Failed to add duplicate label to #{issue_num}: {result.stderr}")
            except Exception as e:
                print(f"  Error processing #{issue_num}: {str(e)}")
    
    print("\nApplying 'duplicate' label to other AI Agent Framework issues...")
    for issue_num in [num for num in framework_issues if num != 2687]:  # Skip the one we already tagged
        try:
            result = subprocess.run(['gh', 'issue', 'edit', str(issue_num), '--add-label', 'duplicate'], 
                                  cwd='/Users/huohao/Repositories/ossinsight', 
                                  capture_output=True, text=True)
            if result.returncode == 0:
                print(f"  Successfully added duplicate label to #{issue_num}")
            else:
                print(f"  Failed to add duplicate label to #{issue_num}: {result.stderr}")
        except Exception as e:
            print(f"  Error processing #{issue_num}: {str(e)}")

if __name__ == "__main__":
    main()